// 拆点
struct node {
	ll id, st, d;
	bool operator<(const node& a)const {
		return a.d < d;
	}
};
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	int s, t; cin >> s >> t;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var dis = Vec2<int>(n + 1, 2, INF);
	var cnt = Vec2<ll>(n + 1, 2);
	var vis = Vec2<bool>(n + 1, 2);
	var Q = priority_queue<node>();
	dis[s][0] = 0, cnt[s][0] = 1;

	Q.push({ s,0 });
	while (Q.size()) {
		var[now, st, d] = Q.top();
		Q.pop();

		if (vis[now][st])continue;
		vis[now][st] = 1;

		int ndis = dis[now][st] + 1;
		int ncnt = cnt[now][st];

		for (int to : g[now]) {
			if (dis[to][0] > ndis) {
				if (dis[to][0] != dis[to][1]) {
					dis[to][1] = dis[to][0];
					cnt[to][1] = cnt[to][0];
					Q.push({ to, 1, dis[to][1] });
				}
				dis[to][0] = ndis;
				cnt[to][0] = ncnt;
				Q.push({ to, 0, dis[to][0] });
			}
			else if (dis[to][0] == ndis) {
				cnt[to][0] = (cnt[to][0] + ncnt) % mod;
			}
			else if (dis[to][1] > ndis) {
				dis[to][1] = ndis;
				cnt[to][1] = ncnt;
				Q.push({ to, 1, dis[to][1] });
			}
			else if (dis[to][1] == ndis) {
				cnt[to][1] = (cnt[to][1] + ncnt) % mod;
			}
		}
	}

	ll ans = cnt[t][0];
	if (dis[t][1] - dis[t][0] == 1)ans = (ans + cnt[t][1]) % mod;
	cout << ans << endl;
	return;
}

// 两次 bfs 后，枚举多余边
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	int s, t; cin >> s >> t;
	var g = vector<vector<int>>(n + 1);
	var p = vector<pii>();
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		p.pb({ u,v });
		g[u].pb(v), g[v].pb(u);
	}

	var dis = Vec2<ll>(2, n + 1, INF);
	var cnt = Vec2<ll>(2, n + 1);
	var dij = [&](int s, vector<ll>& dis, vector<ll>& cnt)->void {
		var vis = vector<int>(n + 1);
		var Q = queue<int>();
		dis[s] = 0, cnt[s] = 1;
		Q.push(s);
		while (Q.size()) {
			int now = Q.front();
			Q.pop();
			if (vis[now])continue;
			vis[now] = 1;
			for (int to : g[now]) {
				if (dis[to] > dis[now] + 1) {
					dis[to] = dis[now] + 1;
					cnt[to] = cnt[now];
					Q.push(to);
				}
				else if (dis[to] == dis[now] + 1) {
					cnt[to] = (cnt[to] + cnt[now]) % mod;
					Q.push(to);
				}
			}
		}
		};
	dij(s, dis[0], cnt[0]);
	dij(t, dis[1], cnt[1]);

	ll ans = cnt[0][t];
	for (const var& [x, y] : p) {
		if (dis[0][x] == dis[0][y]) {
			// 说明 x - y 是多余边
			if (dis[0][x] + dis[1][y] == dis[0][t]) 
				// 走了多余边 x - y，距离就为 dis[0][t] + 1
				ans = (ans + cnt[0][x] * cnt[1][y] % mod) % mod;
			if (dis[1][x] + dis[0][y] == dis[0][t])
				ans = (ans + cnt[1][x] * cnt[0][y] % mod) % mod;
		}
	}
	cout << ans << endl;
	return;
}
